import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const x=JSON.parse('{"title":"明城墙遗址","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/city-wall.md","filePath":"landmarks/city-wall.md","lastUpdated":null}'),n={name:"landmarks/city-wall.md"};function i(o,t,d,s,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="明城墙遗址" tabindex="-1">明城墙遗址 <a class="header-anchor" href="#明城墙遗址" aria-label="Permalink to &quot;明城墙遗址&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1599661046289-e31897846e41?w=1200" alt="明城墙遗址"></p><blockquote><p>&quot;古都最后的记忆，明清城墙的残存。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>明城墙遗址位于北京市东城区，是北京内城仅存的一段明城墙遗址。这段城墙始建于明永乐年间，距今已有600余年历史。遗址公园以古城墙为主体，配以绿化景观，是了解北京古城墙历史的好去处。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:00-17:30</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">10元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线建国门站或东便门站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区崇文门东大街9号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="明城墙修建" tabindex="-1">明城墙修建 <a class="header-anchor" href="#明城墙修建" aria-label="Permalink to &quot;明城墙修建&quot;">​</a></h3><p>明永乐元年（1403年），明成祖朱棣决定迁都北京。永乐四年（1406年）开始营建北京城，永乐十八年（1420年）建成。北京城墙全长24公里，设城门9座。</p><h3 id="城墙拆除" tabindex="-1">城墙拆除 <a class="header-anchor" href="#城墙拆除" aria-label="Permalink to &quot;城墙拆除&quot;">​</a></h3><p>1950年代至1970年代，北京城墙大部分被拆除，用于修建地铁和道路。目前仅存崇文门至东南城角的一段，长约1.5公里。</p><h3 id="遗址公园" tabindex="-1">遗址公园 <a class="header-anchor" href="#遗址公园" aria-label="Permalink to &quot;遗址公园&quot;">​</a></h3><p>1996年，明城墙遗址被列为全国重点文物保护单位。2003年，明城墙遗址公园建成开放，成为展示北京古城墙历史的重要场所。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="城墙结构" tabindex="-1">城墙结构 <a class="header-anchor" href="#城墙结构" aria-label="Permalink to &quot;城墙结构&quot;">​</a></h3><p>明城墙遗址保存了明清北京城墙的典型结构：</p><ul><li><strong>城墙</strong>：高约11米，底宽约15米，顶宽约12米</li><li><strong>外包砖</strong>：城墙外壁包砌城砖</li><li><strong>内填土</strong>：城墙内部夯土填充</li><li><strong>垛口</strong>：城墙顶部有垛口，用于防御</li></ul><h3 id="东南角楼" tabindex="-1">东南角楼 <a class="header-anchor" href="#东南角楼" aria-label="Permalink to &quot;东南角楼&quot;">​</a></h3><p>东南角楼是明城墙遗址的重要组成部分，是北京内城四座角楼中仅存的一座。</p><h4 id="建筑特点" tabindex="-1">建筑特点 <a class="header-anchor" href="#建筑特点" aria-label="Permalink to &quot;建筑特点&quot;">​</a></h4><ul><li><strong>形制</strong>：重檐歇山顶，灰筒瓦绿剪边</li><li><strong>结构</strong>：两层，平面呈曲尺形</li><li><strong>箭窗</strong>：四面共有箭窗144个</li><li><strong>高度</strong>：总高约30米</li></ul><h4 id="历史价值" tabindex="-1">历史价值 <a class="header-anchor" href="#历史价值" aria-label="Permalink to &quot;历史价值&quot;">​</a></h4><p>东南角楼是中国现存最大、最早的城垣转角箭楼，是北京古城的重要标志。</p><h3 id="墩台" tabindex="-1">墩台 <a class="header-anchor" href="#墩台" aria-label="Permalink to &quot;墩台&quot;">​</a></h3><p>城墙外侧有凸出的墩台，是城墙防御体系的组成部分，用于侧翼射击。</p><h2 id="游览区域" tabindex="-1">游览区域 <a class="header-anchor" href="#游览区域" aria-label="Permalink to &quot;游览区域&quot;">​</a></h2><h3 id="城墙遗址" tabindex="-1">城墙遗址 <a class="header-anchor" href="#城墙遗址" aria-label="Permalink to &quot;城墙遗址&quot;">​</a></h3><p>沿着城墙遗址漫步，可以感受600年的历史沧桑。城墙上设有步道，可以登高远眺。</p><h3 id="东南角楼-1" tabindex="-1">东南角楼 <a class="header-anchor" href="#东南角楼-1" aria-label="Permalink to &quot;东南角楼&quot;">​</a></h3><p>登上东南角楼，俯瞰北京城，想象古代北京城墙的雄伟。</p><h3 id="绿地公园" tabindex="-1">绿地公园 <a class="header-anchor" href="#绿地公园" aria-label="Permalink to &quot;绿地公园&quot;">​</a></h3><p>城墙遗址公园种植了大量绿植，是北京市民休闲的好去处。</p><h2 id="历史反思" tabindex="-1">历史反思 <a class="header-anchor" href="#历史反思" aria-label="Permalink to &quot;历史反思&quot;">​</a></h2><p>明城墙的拆除是北京城市发展史上的一大遗憾。著名建筑学家梁思成曾极力主张保护古城墙，提出将城墙改造为环城公园的设想，但未被采纳。</p><p>如今，站在残存的城墙前，我们不仅要感叹历史的沧桑，更要反思城市发展中如何保护历史文化遗产。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>城墙漫步（约1-2小时）</strong>：</p><p>从崇文门端进入 → 沿城墙步道向东 → 登上东南角楼 → 继续向东 → 至东便门端</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点/路线</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">2号线建国门站C口或东便门站</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">8路、12路、17路等崇文门站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从崇文门步行约10分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>门票便宜</strong>：门票仅10元，物超所值</li><li><strong>人少清静</strong>：游客不多，适合慢慢游览</li><li><strong>拍照地点</strong>：东南角楼是绝佳拍照点</li><li><strong>结合游览</strong>：可与崇文门、北京站一起游览</li><li><strong>傍晚时分</strong>：傍晚光线柔和，适合拍照</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">北京站</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">老火车站</td></tr><tr><td style="text-align:left;">崇文门</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">老城门</td></tr><tr><td style="text-align:left;">东单</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">商业区</td></tr><tr><td style="text-align:left;">王府井</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">商业街</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市东城区崇文门东大街9号 <strong>📞 电话</strong>：010-65270578</p>',48)])])}const b=a(n,[["render",i]]);export{x as __pageData,b as default};
